# ----------------------------------
# 🌿 Persistent JSON Memory Store (ChromaDB Fallback)
# ----------------------------------

class ChromaMemory:
    """
    A 100% compatible, pure-python persistent JSON memory database.
    Replaces ChromaDB to completely eliminate third-party warnings and compatibility crashes on Python 3.14.
    Supports persistent storage, speakers, valence, and keyword-overlap semantic memory recall.
    """
    import threading
    _file_lock = threading.Lock()

    def __init__(self, persist_directory="isa_memory"):
        self.persist_path = os.path.join(persist_directory, "conversations.json")
        self.profile_path = os.path.join(persist_directory, "profile.json")
        # Ensure directory exists
        if not os.path.exists(persist_directory):
            try:
                os.makedirs(persist_directory)
            except Exception:
                pass
        self.history = self.load_history()
        self.profile = self.load_profile()

    def load_profile(self):
        with self._file_lock:
            profile = None
            if os.path.exists(self.profile_path):
                try:
                    with open(self.profile_path, "r", encoding="utf-8") as f:
                        profile = json.load(f)
                except Exception:
                    pass
        if not profile:
            profile = self.get_default_profile()
            
        if profile.get("name") == "Sweetie":
            profile["name"] = "Friend"
            
        # Ensure all new fields exist
        defaults = {
            "diary": [],
            "cozy_points": 100,
            "room_decorations": [],
            "unlocked_photos": [],
            "achievements": [],
            "character": "kazumi",
            "quests": {
                "active": [
                    {"id": "chat", "desc": "Chat with Kazumi (5 messages)", "target": 5, "progress": 0, "points": 20},
                    {"id": "gift", "desc": "Give a sweet gift", "target": 1, "progress": 0, "points": 30},
                    {"id": "game", "desc": "Win any mini-game", "target": 1, "progress": 0, "points": 40}
                ],
                "last_update": time.time()
            },
            "psychology": {
                "avg_word_count": 10.0,
                "msg_count": 0,
                "dominant_vibe": "Neutral",
                "interaction_preference": "Casual Conversation",
                "rolling_valence": 0.0
            },
            "zodiac": "None",
            "horoscope_date": "None",
            "baked_inventory": {}
        }
        for k, v in defaults.items():
            if k not in profile:
                profile[k] = v
        return profile

    def get_default_profile(self):
        return {
            "name": "Friend",
            "favorite_drink": "None",
            "birthday": "None",
            "hobbies": [],
            "affection_level": 50,
            "gifts_given": {},
            "diary": [],
            "cozy_points": 100,
            "room_decorations": [],
            "unlocked_photos": [],
            "achievements": [],
            "quests": {
                "active": [
                    {"id": "chat", "desc": "Chat with Kazumi (5 messages)", "target": 5, "progress": 0, "points": 20},
                    {"id": "gift", "desc": "Give a sweet gift", "target": 1, "progress": 0, "points": 30},
                    {"id": "game", "desc": "Win any mini-game", "target": 1, "progress": 0, "points": 40}
                ],
                "last_update": time.time()
            },
            "psychology": {
                "avg_word_count": 10.0,
                "msg_count": 0,
                "dominant_vibe": "Neutral",
                "interaction_preference": "Casual Conversation",
                "rolling_valence": 0.0
            },
            "zodiac": "None",
            "horoscope_date": "None",
            "baked_inventory": {}
        }

    def save_profile(self):
        with self._file_lock:
            try:
                with open(self.profile_path, "w", encoding="utf-8") as f:
                    json.dump(self.profile, f, ensure_ascii=False, indent=2)
            except Exception:
                pass

    def load_history(self):
        with self._file_lock:
            if os.path.exists(self.persist_path):
                try:
                    with open(self.persist_path, "r", encoding="utf-8") as f:
                        return json.load(f)
                except Exception:
                    return []
            return []

    def save_history(self):
        with self._file_lock:
            try:
                with open(self.persist_path, "w", encoding="utf-8") as f:
                    json.dump(self.history, f, ensure_ascii=False, indent=2)
            except Exception:
                pass

    def add(self, text, speaker="user", valence=0.0, session_id=None):
        if session_id is None:
            session_id = getattr(self, "current_session_id", None)
        self.history.append({
            "text": text,
            "speaker": speaker,
            "valence": float(valence),
            "timestamp": time.time(),
            "session_id": session_id
        })
        self.save_history()

    def recall(self, text, top_k=3, speaker_filter=None):
        query_words = set(re.findall(r"\b\w+\b", text.lower())) - STOP_WORDS
        if not query_words:
            # Fallback to most recent messages
            matching = [item["text"] for item in self.history if not speaker_filter or item["speaker"] == speaker_filter]
            results = []
            seen = set()
            for msg in reversed(matching):
                norm_msg = msg.strip().lower()
                if norm_msg not in seen:
                    seen.add(norm_msg)
                    results.insert(0, msg)
                if len(results) >= top_k:
                    break
            return results
            
        scored_docs = []
        for item in self.history:
            if speaker_filter and item["speaker"] != speaker_filter:
                continue
            doc_words = set(re.findall(r"\b\w+\b", item["text"].lower())) - STOP_WORDS
            overlap = len(query_words.intersection(doc_words))
            if overlap > 0:
                scored_docs.append((overlap, item["text"]))
                
        # Sort by score descending
        scored_docs.sort(key=lambda x: x[0], reverse=True)
        
        results = []
        seen = set()
        for overlap, doc in scored_docs:
            norm_doc = doc.strip().lower()
            if norm_doc not in seen:
                seen.add(norm_doc)
                results.append(doc)
            if len(results) >= top_k:
                break
        
        # Fallback to most recent messages if no keyword matches
        if not results:
            matching = [item["text"] for item in self.history if not speaker_filter or item["speaker"] == speaker_filter]
            seen = set()
            for msg in reversed(matching):
                norm_msg = msg.strip().lower()
                if norm_msg not in seen:
                    seen.add(norm_msg)
                    results.insert(0, msg)
                if len(results) >= top_k:
                    break
            
        return results


