    def get_archetype_reaction(self, reactions_dict):
        arch_key = "TEASING" if self.active_character == "mimi" else "DEREDERE"
        react = reactions_dict.get(arch_key)
        if not react:
            react = reactions_dict.get("DEREDERE")
        if not react:
            react = list(reactions_dict.values())[0] if reactions_dict else ""
        return react

    def add_affection(self, base_gain):
        profile = self.memory.profile
        curr_aff = profile.get("affection_level", 50)
        if curr_aff < 30:
            factor = 0.25
        elif curr_aff < 50:
            factor = 0.15
        elif curr_aff < 75:
            factor = 0.08
        elif curr_aff < 90:
            factor = 0.04
        else:
            factor = 0.01
        
        # Calculate raw gain (allowing fractional parts as probability for +1)
        raw_gain = base_gain * factor
        gain = int(raw_gain)
        fractional = raw_gain - gain
        if random.random() < fractional:
            gain += 1
            
        new_aff = min(100, curr_aff + gain)
        profile["affection_level"] = new_aff
        self.memory.save_profile()
        return gain

    def clean_roleplay(self, text):
        if not text:
            return text
        
        # Action stems representing third-person narrative actions
        action_stems = r'giggle|smile|pout|blush|nod|tap|hug|wink|sigh|laugh|whisper|turn|look|write|think|say|wave|shrug|yawn|clap|cheer|gasp|cry|point|hold|kazumi|isa|\bshe\b|\bher\b|giggle|cough|sneeze|clear.*throat'
        
        # Strip narrative actions wrapped in asterisks while preserving markdown headers
        def replace_asterisks(match):
            content = match.group(0)
            content_lower = content.lower()
            if ":" in content_lower:
                return content
            if re.search(action_stems, content_lower):
                return ""
            return content

        text = re.sub(r'\*.*?\*', replace_asterisks, text)
        
        # Strip parenthetical narrative actions, preserving instructions and non-action notes
        def replace_parens(match):
            content = match.group(0)
            content_lower = content.lower()
            if ":" in content_lower:
                return content
            if re.search(r'\d|type|choose|select|option|guess|enter|press|inventory|shop|points|cp|round|match|nudge|system|reminder|step|time', content_lower):
                return content
            if re.search(action_stems, content_lower):
                return ""
            return content
            
        text = re.sub(r'\(.*?\)', replace_parens, text)
        
        # Normalize spaces and punctuation spacing
        text = re.sub(r'\s+', ' ', text)
        text = re.sub(r'\s+([.,!?])', r'\1', text)
        return text.strip()

    def sanitize_endearments(self, text):
        if not text:
            return text
        profile = self.memory.profile
        aff = profile.get("affection_level", 50)
        uname = profile.get("name", "Friend")
        if uname == "Sweetie":
            uname = "Friend"
            profile["name"] = "Friend"
            self.memory.save_profile()
            
        if aff >= 100:
            return text
            
        # Protect 'honey' from matching when it is used as an ingredient (preceded by lavender or followed by tea, latte, comb, etc.)
        pattern = r'\b(sweetie|darling|sweetheart|my\s+love|dearest|babe|baby|(?<!lavender\s)honey(?!\s+(tea|latte|syrup|comb|mustard|glaze|dew|suckle|dust|sauce|bun|cake|milk))|dear(?!\s+(diary|friend)))\b'
        
        def replace_match(match):
            return uname if uname != "Friend" else "friend"
            
        text = re.sub(pattern, replace_match, text, flags=re.IGNORECASE)
        return text

